+    use super::*;
+    use crate::types::RegistryProvider;
+
+    fn configured(provider: RegistryProvider) -> PackageRegistryConnector {
+        let mut connector = PackageRegistryConnector::new();
+        fcp_async_core::runtime::block_on_sync(async {
+            connector
+                .configure(json!({
